ValidationRule.errorConditionFormula:
If( ISNEW(), (AND(OR(ISNULL( CreatedDate ),ISBLANK(CreatedDate )),AND( ISPICKVAL(Insolvency_Status__c, "Sent to Collections"), ISPICKVAL(PRIORVALUE(Insolvency_Status__c), "Sent to Collections"), ISPICKVAL(Insolvency_Status__c, "Withdraw PoC"), OR( $Profile.Name = "Fairstone Community User", $Profile.Name = "Goeasy Community User"
) ))), AND( ISPICKVAL(Insolvency_Status__c, "Sent to Collections"), ISPICKVAL(PRIORVALUE(Insolvency_Status__c), "Sent to Collections"), ISPICKVAL(Insolvency_Status__c, "Withdraw PoC"), OR( $Profile.Name = "Fairstone Community User", $Profile.Name = "Goeasy Community User"
) ))
